) -> Option<String> {
    attr_optional_string(attributes, key)
}

fn attr_optional_string(
    attributes: &std::collections::HashMap<String, serde_json::Value>,
    key: &str,
) -> Option<String> {
    attributes
        .get(key)
        .and_then(serde_json::Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToOwned::to_owned)
}

