fn parse_query_enum<T: serde::de::DeserializeOwned>(
    params: &HashMap<&str, &str>,
    key: &str,
) -> Option<T> {
    params
        .get(key)
        .and_then(|v| serde_json::from_value(serde_json::Value::String((*v).to_string())).ok())
}

impl From<storage::SessionRow> for SessionSummary {
